import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 純弓兵流終極指南：讓敵人死在衝鋒的路上","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/archer-only.md","filePath":"bannerlord/archer-only.md"}'),i={name:"bannerlord/archer-only.md"};function o(n,t,d,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="騎砍2-純弓兵流終極指南-讓敵人死在衝鋒的路上" tabindex="-1">騎砍2 | 純弓兵流終極指南：讓敵人死在衝鋒的路上 <a class="header-anchor" href="#騎砍2-純弓兵流終極指南-讓敵人死在衝鋒的路上" aria-label="Permalink to &quot;騎砍2 | 純弓兵流終極指南：讓敵人死在衝鋒的路上&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>弓兵流是最安逸的玩法——站在高處看著敵人被箭雨淹沒，你甚至不用拔劍。但弓兵怕騎兵衝鋒、怕近身、需要地形配合。</p><hr><h2 id="一、純弓兵流的優勢" tabindex="-1">一、純弓兵流的優勢 <a class="header-anchor" href="#一、純弓兵流的優勢" aria-label="Permalink to &quot;一、純弓兵流的優勢&quot;">​</a></h2><ul><li><strong>傷害最高</strong>：巴坦尼亞費奧納勇士，280 弓術</li><li><strong>零戰損</strong>：敵人沒走到你面前就死光了</li><li><strong>攻城極強</strong>：壓制城牆守軍無敵</li><li><strong>不太需要微操</strong>：F4 自由射擊，看戲就好</li></ul><hr><h2 id="二、純弓兵流的劣勢" tabindex="-1">二、純弓兵流的劣勢 <a class="header-anchor" href="#二、純弓兵流的劣勢" aria-label="Permalink to &quot;二、純弓兵流的劣勢&quot;">​</a></h2><ul><li><strong>怕騎兵衝鋒</strong>：騎兵衝進弓兵群 = 屠殺</li><li><strong>需要高地</strong>：平地弓兵效果打折</li><li><strong>怕森林</strong>：樹木擋箭</li><li><strong>近戰是紙糊的</strong>：被貼身就完了</li></ul><hr><h2 id="三、最佳兵種配置" tabindex="-1">三、最佳兵種配置 <a class="header-anchor" href="#三、最佳兵種配置" aria-label="Permalink to &quot;三、最佳兵種配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>兵種</th><th style="text-align:center;">佔比</th><th>用途</th></tr></thead><tbody><tr><td>巴坦尼亞費奧納勇士</td><td style="text-align:center;">60%</td><td>主力輸出</td></tr><tr><td>瓦蘭迪亞弩手</td><td style="text-align:center;">20%</td><td>打重甲單位，破甲</td></tr><tr><td>帝國軍團步兵</td><td style="text-align:center;">20%</td><td>保護弓兵，擋騎兵</td></tr></tbody></table><blockquote><p>純弓兵流還是需要一些步兵擋前排，不然騎兵一衝就崩。</p></blockquote><hr><h2 id="四、戰術操作" tabindex="-1">四、戰術操作 <a class="header-anchor" href="#四、戰術操作" aria-label="Permalink to &quot;四、戰術操作&quot;">​</a></h2><h3 id="_4-1-陣地架設" tabindex="-1">4.1 陣地架設 <a class="header-anchor" href="#_4-1-陣地架設" aria-label="Permalink to &quot;4.1 陣地架設&quot;">​</a></h3><ol><li>開場立刻找高地</li><li>弓兵 F3+F2（散開陣型）放在高地上</li><li>步兵在山腳下列盾牆</li><li>你自己站弓兵群中（你的技能會加成最近的部隊）</li></ol><h3 id="_4-2-射擊節奏" tabindex="-1">4.2 射擊節奏 <a class="header-anchor" href="#_4-2-射擊節奏" aria-label="Permalink to &quot;4.2 射擊節奏&quot;">​</a></h3><ul><li>敵方距離遠 → F4 自由射擊</li><li>敵方距離中 → 不要動，繼續射</li><li>敵方距離近（快到步兵了）→ F4 停火 → 步兵上前 → 弓兵後退一段距離繼續射</li></ul><h3 id="_4-3-應對騎兵" tabindex="-1">4.3 應對騎兵 <a class="header-anchor" href="#_4-3-應對騎兵" aria-label="Permalink to &quot;4.3 應對騎兵&quot;">​</a></h3><ul><li>步兵開盾牆擋在弓兵前面</li><li>弓兵站高處可以射得更遠</li><li>地圖選森林/山區 = 廢掉敵方騎兵</li></ul><hr><h2 id="五、不同文化的替代方案" tabindex="-1">五、不同文化的替代方案 <a class="header-anchor" href="#五、不同文化的替代方案" aria-label="Permalink to &quot;五、不同文化的替代方案&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文化</th><th>替代弓兵</th><th style="text-align:center;">評價</th></tr></thead><tbody><tr><td>阿塞萊</td><td>阿塞萊弓手（有盾牌！）</td><td style="text-align:center;">生存力強</td></tr><tr><td>帝國</td><td>帝國禁衛弓兵</td><td style="text-align:center;">中規中矩</td></tr><tr><td>斯特吉亞</td><td>不建議純弓兵</td><td style="text-align:center;">他們弓手太弱</td></tr></tbody></table><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./cavalry-only.html">騎砍2 | 純騎兵流終極指南</a></li><li><a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',33)])])}const g=a(i,[["render",o]]);export{b as __pageData,g as default};
